+    fn scenario_runner_normalizes_whitespace_ids() {
+        crate::test_utils::init_test_logging();
+        crate::test_phase!("scenario_runner_normalizes_whitespace_ids");
+
+        let mut runner = SporkScenarioRunner::new();
+        runner
